{
  "name": "Repasse Pro - Calculadora de Veículos",
  "description": "Calculadora profissional para repasse de veículos, focada em ROI, custo de oportunidade e margem líquida."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum CalcMode {
  SALE_TO_PROFIT = 'SALE_TO_PROFIT',
  PROFIT_TO_SALE = 'PROFIT_TO_SALE'
}

export interface AppState {
  mode: CalcMode;
  carPrice: number;
  purchaseDate: string;
  saleDate: string;
  opportunityRate: number;
  freight: number;
  taxRate: number;
  targetSalePrice: number;
  targetNetProfit: number;
  quality: number;
}

export interface CalcResults {
  days: number;
  oppCost: number;
  invBase: number;
  totalCost: number;
  salePrice: number;
  grossProfit: number;
  taxAmount: number;
  netProfit: number;
  roi: number;
  error?: string;
}

import { AppState, CalcResults, CalcMode } from '../types';

export const calculateResults = (state: AppState): CalcResults => {
  const {
    mode,
    carPrice,
    purchaseDate,
    saleDate,
    opportunityRate,
    freight,
    taxRate,
    targetSalePrice,
    targetNetProfit
  } = state;

  // Validation
  const d1 = new Date(purchaseDate);
  const d2 = new Date(saleDate);

  if (isNaN(d1.getTime()) || isNaN(d2.getTime())) {
    return createEmptyResults("Datas inválidas");
  }

  const diffTime = d2.getTime() - d1.getTime();
  const days = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  if (days < 0) {
    return createEmptyResults("Data de venda anterior à compra");
  }

  // Opportunity Cost
  const dailyRate = (opportunityRate / 100) / 365;
  const oppCost = carPrice * dailyRate * days;

  const invBase = carPrice + oppCost;
  const totalCost = invBase + freight;

  let salePrice = 0;
  let netProfit = 0;
  let grossProfit = 0;
  let taxAmount = 0;

  if (mode === CalcMode.SALE_TO_PROFIT) {
    salePrice = targetSalePrice;
    grossProfit = salePrice - totalCost;
    taxAmount = grossProfit > 0 ? grossProfit * (taxRate / 100) : 0;
    netProfit = grossProfit - taxAmount;
  } else {
    // Mode: Profit to Sale
    // netProfit = grossProfit - (grossProfit * taxRate/100)
    // netProfit = grossProfit * (1 - taxRate/100)
    // grossProfit = netProfit / (1 - taxRate/100)
    netProfit = targetNetProfit;
    const factor = (1 - (taxRate / 100));
    grossProfit = factor > 0 ? netProfit / factor : netProfit;
    salePrice = totalCost + grossProfit;
    taxAmount = grossProfit > 0 ? grossProfit * (taxRate / 100) : 0;
  }

  const roi = invBase > 0 ? (netProfit / invBase) * 100 : 0;

  return {
    days,
    oppCost,
    invBase,
    totalCost,
    salePrice,
    grossProfit,
    taxAmount,
    netProfit,
    roi
  };
};

const createEmptyResults = (error: string): CalcResults => ({
  days: 0,
  oppCost: 0,
  invBase: 0,
  totalCost: 0,
  salePrice: 0,
  grossProfit: 0,
  taxAmount: 0,
  netProfit: 0,
  roi: 0,
  error
});

export const formatBRL = (val: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(val);
};

export const formatPercent = (val: number) => {
  return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + '%';
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AppState, CalcMode } from './types';
import { calculateResults, formatBRL, formatPercent } from './services/calculatorService';

const STORAGE_KEY = 'repasse_pro_data';

const INITIAL_STATE: AppState = {
  mode: CalcMode.SALE_TO_PROFIT,
  carPrice: 0,
  purchaseDate: new Date().toISOString().split('T')[0],
  saleDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  opportunityRate: 12.0,
  freight: 0,
  taxRate: 15.0,
  targetSalePrice: 0,
  targetNetProfit: 0,
  quality: 3
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        return INITIAL_STATE;
      }
    }
    return INITIAL_STATE;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const results = useMemo(() => calculateResults(state), [state]);

  const handleInputChange = (field: keyof AppState, value: any) => {
    setState(prev => ({ ...prev, [field]: value }));
  };

  const handleNumericInput = (field: keyof AppState, e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value.replace(',', '.');
    const numeric = parseFloat(val);
    setState(prev => ({ ...prev, [field]: isNaN(numeric) ? 0 : numeric }));
  };

  const clearData = () => {
    if (confirm('Deseja limpar todos os dados?')) {
      setState(INITIAL_STATE);
    }
  };

  const copyResults = useCallback(() => {
    const text = `
📊 *AVALIAÇÃO DE REPASSE*
🚗 Qualidade: ${state.quality}/5
💰 Preço Carro: ${formatBRL(state.carPrice)}
📅 Período: ${results.days} dias
📈 Custo Oportunidade: ${formatBRL(results.oppCost)}
🚚 Frete: ${formatBRL(state.freight)}
💵 Custo Total: ${formatBRL(results.totalCost)}
---
🏷️ Preço Venda: ${formatBRL(results.salePrice)}
📉 Imposto (${state.taxRate}%): ${formatBRL(results.taxAmount)}
💎 Lucro Líquido: ${formatBRL(results.netProfit)}
🚀 ROI: ${formatPercent(results.roi)}
    `.trim();

    navigator.clipboard.writeText(text).then(() => {
      alert('Resultados copiados para a área de transferência!');
    });
  }, [state, results]);

  const shareResults = useCallback(() => {
    const text = `Avaliação de Repasse: Lucro Líquido ${formatBRL(results.netProfit)} | ROI ${formatPercent(results.roi)}`;
    if (navigator.share) {
      navigator.share({
        title: 'Repasse Pro',
        text: text,
      }).catch(console.error);
    } else {
      copyResults();
    }
  }, [results, copyResults]);

  const getQualityColor = (val: number) => {
    const hue = (val - 1) * 30; // 1=0 (Red), 5=120 (Green)
    return `hsl(${hue}, 70%, 50%)`;
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-slate-50 pb-24">
      {/* Header */}
      <header className="bg-indigo-700 text-white p-6 shadow-md rounded-b-3xl">
        <h1 className="text-2xl font-bold flex items-center gap-2">
          <span>🚗</span> Repasse Pro
        </h1>
        <p className="text-indigo-100 text-sm mt-1">Calculadora rápida de lucro e ROI</p>
      </header>

      <main className="px-4 py-6 space-y-6">
        {/* Mode Selector */}
        <div className="bg-white p-1 rounded-xl shadow-sm flex border border-slate-200">
          <button
            onClick={() => handleInputChange('mode', CalcMode.SALE_TO_PROFIT)}
            className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${
              state.mode === CalcMode.SALE_TO_PROFIT ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-600'
            }`}
          >
            Preço → Lucro
          </button>
          <button
            onClick={() => handleInputChange('mode', CalcMode.PROFIT_TO_SALE)}
            className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${
              state.mode === CalcMode.PROFIT_TO_SALE ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-600'
            }`}
          >
            Lucro → Preço
          </button>
        </div>

        {/* Input Form */}
        <section className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2">
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Preço do Veículo (R$)</label>
              <input
                type="number"
                inputMode="decimal"
                value={state.carPrice || ''}
                onChange={(e) => handleNumericInput('carPrice', e)}
                placeholder="Ex: 50000"
                className="w-full bg-slate-50 border border-slate-200 rounded-lg p-3 text-lg font-semibold focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Compra</label>
              <input
                type="date"
                value={state.purchaseDate}
                onChange={(e) => handleInputChange('purchaseDate', e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-lg p-2 text-sm"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Venda</label>
              <input
                type="date"
                value={state.saleDate}
                onChange={(e) => handleInputChange('saleDate', e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-lg p-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tx. Oport. (% a.a.)</label>
              <input
                type="number"
                value={state.opportunityRate}
                onChange={(e) => handleNumericInput('opportunityRate', e)}
                className="w-full bg-slate-50 border border-slate-200 rounded-lg p-2 text-sm"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Imposto (%)</label>
              <input
                type="number"
                value={state.taxRate}
                onChange={(e) => handleNumericInput('taxRate', e)}
                className="w-full bg-slate-50 border border-slate-200 rounded-lg p-2 text-sm"
              />
            </div>

            <div className="col-span-2">
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Frete / Gastos Extras (R$)</label>
              <input
                type="number"
                value={state.freight || ''}
                onChange={(e) => handleNumericInput('freight', e)}
                className="w-full bg-slate-50 border border-slate-200 rounded-lg p-2 text-sm"
              />
            </div>

            <div className="col-span-2 pt-2 border-t border-slate-100">
              {state.mode === CalcMode.SALE_TO_PROFIT ? (
                <>
                  <label className="block text-xs font-bold text-indigo-600 uppercase mb-1">Preço de Venda Pretendido (R$)</label>
                  <input
                    type="number"
                    inputMode="decimal"
                    value={state.targetSalePrice || ''}
                    onChange={(e) => handleNumericInput('targetSalePrice', e)}
                    className="w-full bg-indigo-50 border border-indigo-100 rounded-lg p-3 text-lg font-bold text-indigo-900 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  />
                </>
              ) : (
                <>
                  <label className="block text-xs font-bold text-emerald-600 uppercase mb-1">Lucro Líquido Desejado (R$)</label>
                  <input
                    type="number"
                    inputMode="decimal"
                    value={state.targetNetProfit || ''}
                    onChange={(e) => handleNumericInput('targetNetProfit', e)}
                    className="w-full bg-emerald-50 border border-emerald-100 rounded-lg p-3 text-lg font-bold text-emerald-900 focus:outline-none focus:ring-2 focus:ring-emerald-500"
                  />
                </>
              )}
            </div>
          </div>
        </section>

        {/* Quality Score */}
        <section className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-center mb-4">
            <label className="text-xs font-bold text-slate-500 uppercase">Qualidade do Veículo</label>
            <span 
              className="px-3 py-1 rounded-full text-white font-bold text-sm transition-colors duration-300"
              style={{ backgroundColor: getQualityColor(state.quality) }}
            >
              Nota: {state.quality}
            </span>
          </div>
          <input
            type="range"
            min="1"
            max="5"
            step="1"
            value={state.quality}
            onChange={(e) => handleInputChange('quality', parseInt(e.target.value))}
            className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
            style={{ color: getQualityColor(state.quality) }}
          />
          <div className="flex justify-between mt-2 text-[10px] font-bold text-slate-400">
            <span>RUIM</span>
            <span>MÉDIO</span>
            <span>EXCELENTE</span>
          </div>
        </section>

        {/* Results */}
        {results.error ? (
          <div className="bg-red-50 text-red-600 p-4 rounded-xl text-center text-sm font-medium border border-red-100">
            ⚠️ {results.error}
          </div>
        ) : (
          <section className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
                <span className="block text-[10px] font-bold text-slate-400 uppercase">Período</span>
                <span className="text-lg font-bold text-slate-700">{results.days} <small className="text-xs">dias</small></span>
              </div>
              <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
                <span className="block text-[10px] font-bold text-slate-400 uppercase">Custo Oportunidade</span>
                <span className="text-lg font-bold text-amber-600">{formatBRL(results.oppCost)}</span>
              </div>
            </div>

            <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm space-y-3">
              <div className="flex justify-between items-center border-b border-slate-50 pb-2">
                <span className="text-sm text-slate-500">Base Investimento</span>
                <span className="font-semibold text-slate-700">{formatBRL(results.invBase)}</span>
              </div>
              <div className="flex justify-between items-center border-b border-slate-50 pb-2">
                <span className="text-sm text-slate-500">Custo Total Negócio</span>
                <span className="font-semibold text-slate-700">{formatBRL(results.totalCost)}</span>
              </div>
              <div className="flex justify-between items-center border-b border-slate-50 pb-2">
                <span className="text-sm text-slate-500">Imposto ({state.taxRate}%)</span>
                <span className="font-semibold text-red-500">{formatBRL(results.taxAmount)}</span>
              </div>
              <div className="flex justify-between items-center pt-1">
                <span className="text-sm font-bold text-slate-700">Preço Venda</span>
                <span className="text-xl font-black text-indigo-700">{formatBRL(results.salePrice)}</span>
              </div>
            </div>

            <div className="bg-emerald-600 p-6 rounded-3xl shadow-lg text-white relative overflow-hidden">
               <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 pointer-events-none"></div>
               <div className="relative z-10 flex justify-between items-end">
                  <div>
                    <span className="block text-xs font-bold uppercase opacity-80 mb-1">Lucro Líquido</span>
                    <span className="text-3xl font-black">{formatBRL(results.netProfit)}</span>
                  </div>
                  <div className="text-right">
                    <span className="block text-xs font-bold uppercase opacity-80 mb-1">ROI Real</span>
                    <span className="text-2xl font-black">{formatPercent(results.roi)}</span>
                  </div>
               </div>
            </div>
          </section>
        )}
      </main>

      {/* Persistent Call-to-Action */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-4 flex gap-3 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-50">
        <button
          onClick={clearData}
          className="p-3 bg-slate-100 text-slate-500 rounded-xl hover:bg-slate-200 transition-colors"
          title="Limpar"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
        </button>
        <button
          onClick={copyResults}
          className="flex-1 bg-slate-800 text-white font-bold py-3 rounded-xl flex items-center justify-center gap-2 hover:bg-slate-900 transition-all active:scale-95"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3"></path></svg>
          Copiar
        </button>
        <button
          onClick={shareResults}
          className="flex-1 bg-indigo-600 text-white font-bold py-3 rounded-xl flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all active:scale-95"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"></path></svg>
          Compartilhar
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { AppState, CalcMode } from './types';
import { calculateResults, formatBRL, formatPercent } from './services/calculatorService';

const STORAGE_KEY = 'repasse_pro_data_v2';

const INITIAL_STATE: AppState = {
  mode: CalcMode.SALE_TO_PROFIT,
  carPrice: 0,
  purchaseDate: new Date().toISOString().split('T')[0],
  saleDate: new Date(Date.now() + 15 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  opportunityRate: 12.0,
  freight: 0,
  taxRate: 15.0,
  targetSalePrice: 0,
  targetNetProfit: 0,
  quality: 3
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        return INITIAL_STATE;
      }
    }
    return INITIAL_STATE;
  });

  // Auto-persist changes
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const results = useMemo(() => calculateResults(state), [state]);

  const handleInputChange = (field: keyof AppState, value: any) => {
    setState(prev => ({ ...prev, [field]: value }));
  };

  const handleNumericInput = (field: keyof AppState, e: React.ChangeEvent<HTMLInputElement>) => {
    let val = e.target.value;
    // Basic sanitization for commas/points
    val = val.replace(',', '.');
    const numeric = parseFloat(val);
    setState(prev => ({ ...prev, [field]: isNaN(numeric) ? 0 : numeric }));
  };

  const clearData = () => {
    if (confirm('Deseja limpar todos os dados da avaliação atual?')) {
      setState(INITIAL_STATE);
    }
  };

  const copyResults = useCallback(() => {
    const text = `
📊 *REPASSE PRO - AVALIAÇÃO*
🚗 Qualidade: ${state.quality}/5
💰 Preço Carro: ${formatBRL(state.carPrice)}
📅 Período: ${results.days} dias
📈 Custo Oport.: ${formatBRL(results.oppCost)} (${state.opportunityRate}% a.a.)
🚚 Frete: ${formatBRL(state.freight)}
💵 Investimento Total: ${formatBRL(results.totalCost)}
---
🏷️ PREÇO DE VENDA: ${formatBRL(results.salePrice)}
📉 Imposto (${state.taxRate}%): ${formatBRL(results.taxAmount)}
💎 LUCRO LÍQUIDO: ${formatBRL(results.netProfit)}
🚀 ROI: ${formatPercent(results.roi)}
    `.trim();

    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(text).then(() => {
        alert('Copiado com sucesso!');
      }).catch(() => {
        alert('Erro ao copiar. Tente novamente.');
      });
    }
  }, [state, results]);

  const shareResults = useCallback(() => {
    const text = `💰 Repasse: Lucro ${formatBRL(results.netProfit)} | ROI ${formatPercent(results.roi)} no veículo de ${formatBRL(state.carPrice)}`;
    if (navigator.share) {
      navigator.share({
        title: 'Repasse Pro',
        text: text,
      }).catch(() => {
        copyResults();
      });
    } else {
      copyResults();
    }
  }, [results, state.carPrice, copyResults]);

  const getQualityColor = (val: number) => {
    const hue = (val - 1) * 30; // 1=0 (Red), 5=120 (Green)
    return `hsl(${hue}, 70%, 45%)`;
  };

  const roiColorClass = results.roi >= 10 ? 'text-emerald-400' : results.roi > 0 ? 'text-blue-300' : 'text-red-300';

  return (
    <div className="max-w-md mx-auto min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Header */}
      <header className="bg-indigo-600 text-white pt-8 pb-10 px-6 rounded-b-[2.5rem] shadow-lg sticky top-0 z-40">
        <div className="flex justify-between items-start">
          <div>
            <h1 className="text-2xl font-black tracking-tight flex items-center gap-2">
              <span className="bg-white text-indigo-600 px-2 py-0.5 rounded-lg text-xl">R</span>
              REPASSE PRO
            </h1>
            <p className="text-indigo-100 text-xs font-medium uppercase tracking-widest mt-1">Calculadora de Margem & ROI</p>
          </div>
          <button onClick={clearData} className="p-2 bg-white/10 rounded-full active:scale-90 transition-transform">
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
          </button>
        </div>
      </header>

      <main className="px-5 -mt-6 pb-28 space-y-6 relative z-50">
        {/* Calc Mode Toggle */}
        <div className="bg-white p-1.5 rounded-2xl shadow-xl flex border border-slate-100">
          <button
