  mode: CalcMode.SALE_TO_PROFIT,
  carPrice: 0,
  purchaseDate: new Date().toISOString().split('T')[0],
  saleDate: new Date(Date.now() + 15 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  opportunityRateMonthly: 1.0, // Default to 1% per month
  freight: 0,
  taxRate: 15.0,
  targetSalePrice: 0,
  targetNetProfit: 0,
  quality: 3
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Migration check if user had old data
        if (parsed.opportunityRate && !parsed.opportunityRateMonthly) {
          parsed.opportunityRateMonthly = parsed.opportunityRate / 12;
        }
        return parsed;
      } catch (e) {
        return INITIAL_STATE;
      }
    }
    return INITIAL_STATE;
  });

