    setState(prev => ({ ...prev, [field]: value }));
  };

  const handleNumericInput = (field: keyof AppState, e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value.replace(',', '.');
    const numeric = parseFloat(val);
    setState(prev => ({ ...prev, [field]: isNaN(numeric) ? 0 : numeric }));
