/**
 * Componente de Input customizado para lidar com valores decimais brasileiros (vírgula)
 * e garantir que sempre mostre 2 casas decimais ao perder o foco.
 */
interface MoneyInputProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  prefix?: string;
  suffix?: string;
  className?: string;
  labelClassName?: string;
  highlight?: boolean;
}

const MoneyInput: React.FC<MoneyInputProps> = ({ 
  label, value, onChange, prefix, suffix, className, labelClassName, highlight 
}) => {
  // Estado local como string para permitir digitação fluida de vírgula/ponto
  const [displayValue, setDisplayValue] = useState("");

  // Sincroniza o valor externo com o display local (apenas se não estiver focado)
  useEffect(() => {
    const formatted = value.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    setDisplayValue(formatted);
  }, [value]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let raw = e.target.value;
    // Permite apenas números, vírgula e ponto
    raw = raw.replace(/[^0-9.,]/g, '');
    setDisplayValue(raw);

    // Atualiza o estado pai em tempo real para cálculos instantâneos
    const normalized = parseFloat(raw.replace(',', '.'));
    if (!isNaN(normalized)) {
      onChange(normalized);
    } else if (raw === "") {
      onChange(0);
    }
  };

  const handleBlur = () => {
    // Ao sair do campo, garante a formatação de 2 casas decimais
    const numeric = parseFloat(displayValue.replace(',', '.'));
    if (!isNaN(numeric)) {
      setDisplayValue(numeric.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }));
    } else {
      setDisplayValue("0,00");
    }
  };

  return (
    <div className={className}>
      <label className={`text-[10px] font-black uppercase tracking-widest block mb-2 ${labelClassName || 'text-slate-400'}`}>
        {label}
      </label>
      <div className="relative">
        {prefix && <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">{prefix}</span>}
        <input
          type="text"
          inputMode="decimal"
          value={displayValue}
          onChange={handleChange}
          onBlur={handleBlur}
          className={`w-full border-2 rounded-2xl py-3 pr-4 outline-none transition-all font-bold ${prefix ? 'pl-11' : 'pl-4'} ${
            highlight 
              ? 'bg-indigo-50 border-indigo-50 text-indigo-900 focus:border-indigo-500 focus:bg-white' 
              : 'bg-slate-50 border-slate-50 text-slate-800 focus:border-indigo-500 focus:bg-white'
          } ${suffix ? 'pr-10' : ''}`}
        />
        {suffix && <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">{suffix}</span>}
      </div>
    </div>
  );
};

