/**
 * Componente de Input que permite digitação livre.
 * Formata para padrão brasileiro apenas ao sair do campo (onBlur).
 * Atualiza os cálculos em tempo real enquanto o usuário digita.
 */
interface MoneyInputProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  prefix?: string;
  suffix?: string;
  className?: string;
  labelClassName?: string;
  highlight?: boolean;
}

const MoneyInput: React.FC<MoneyInputProps> = ({ 
  label, value, onChange, prefix, suffix, className, labelClassName, highlight 
}) => {
  const [displayValue, setDisplayValue] = useState("");
  const isFocused = useRef(false);

  // Formata o valor numérico para exibição BR
  const formatValue = (val: number) => {
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  // Sincroniza o valor externo apenas quando NÃO está focado (ex: ao limpar dados)
  useEffect(() => {
    if (!isFocused.current) {
      setDisplayValue(value === 0 ? "" : formatValue(value));
    }
  }, [value]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value;
    // Permite digitar números, uma vírgula ou um ponto
    const validChars = raw.replace(/[^0-9.,-]/g, '');
    setDisplayValue(validChars);

    // Tenta converter para número para atualizar os cálculos em tempo real
    // Remove pontos de milhar e troca vírgula por ponto para o parseFloat
    const normalized = parseFloat(validChars.replace(/\./g, '').replace(',', '.'));

    if (!isNaN(normalized)) {
      onChange(normalized);
    } else if (validChars === "") {
      onChange(0);
    }
  };

  const handleFocus = () => {
    isFocused.current = true;
    // Ao focar, limpamos a formatação pesada (pontos de milhar) para facilitar a edição
    if (value !== 0) {
      // Deixamos apenas a vírgula decimal se houver
      setDisplayValue(value.toString().replace('.', ','));
    }
  };

  const handleBlur = () => {
    isFocused.current = false;
    // Ao sair, aplicamos a formatação de 2 casas decimais e pontos de milhar
    const numeric = parseFloat(displayValue.replace(/\./g, '').replace(',', '.'));
    if (!isNaN(numeric)) {
      setDisplayValue(formatValue(numeric));
      onChange(numeric);
    } else {
      setDisplayValue("");
      onChange(0);
    }
  };

  return (
    <div className={className}>
      <label className={`text-[10px] font-black uppercase tracking-widest block mb-1.5 ${labelClassName || 'text-slate-400'}`}>
        {label}
      </label>
      <div className="relative">
        {prefix && (
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold pointer-events-none">
            {prefix}
          </span>
        )}
        <input
          type="text"
          inputMode="decimal"
          value={displayValue}
          onChange={handleChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
          placeholder="0,00"
          className={`w-full border-2 rounded-2xl py-3.5 pr-4 outline-none transition-all font-bold ${prefix ? 'pl-11' : 'pl-4'} ${
            highlight 
              ? 'bg-indigo-50 border-indigo-50 text-indigo-900 focus:border-indigo-500 focus:bg-white' 
              : 'bg-slate-50 border-slate-50 text-slate-800 focus:border-indigo-500 focus:bg-white shadow-sm'
          } ${suffix ? 'pr-10' : ''}`}
        />
        {suffix && (
          <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold pointer-events-none">
            {suffix}
          </span>
        )}
      </div>
    </div>
  );
};

