interface MoneyInputProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  prefix?: string;
  suffix?: string;
  className?: string;
  labelClassName?: string;
  highlight?: boolean;
}

const MoneyInput: React.FC<MoneyInputProps> = ({ 
  label, value, onChange, prefix, suffix, className, labelClassName, highlight 
}) => {
  const [displayValue, setDisplayValue] = useState("");
  const isFocused = useRef(false);

  const formatValue = (val: number) => {
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  useEffect(() => {
    if (!isFocused.current) {
      setDisplayValue(value === 0 ? "" : formatValue(value));
    }
  }, [value]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value;
    const validChars = raw.replace(/[^0-9.,-]/g, '');
    setDisplayValue(validChars);
    const normalized = parseFloat(validChars.replace(/\./g, '').replace(',', '.'));
    if (!isNaN(normalized)) {
      onChange(normalized);
    } else if (validChars === "") {
      onChange(0);
    }
  };

  const handleFocus = () => {
    isFocused.current = true;
    if (value !== 0) {
      setDisplayValue(value.toString().replace('.', ','));
    }
  };

  const handleBlur = () => {
    isFocused.current = false;
    const numeric = parseFloat(displayValue.replace(/\./g, '').replace(',', '.'));
    if (!isNaN(numeric)) {
      setDisplayValue(formatValue(numeric));
      onChange(numeric);
    } else {
      setDisplayValue("");
      onChange(0);
    }
  };

  return (
    <div className={className}>
      <label className={`text-[9px] font-black uppercase tracking-wider block mb-1 ${labelClassName || 'text-slate-400'}`}>
        {label}
      </label>
      <div className="relative">
        {prefix && <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold pointer-events-none">{prefix}</span>}
        <input
          type="text"
          inputMode="decimal"
          value={displayValue}
          onChange={handleChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
          placeholder="0,00"
          className={`w-full border rounded-xl py-2 pr-3 outline-none transition-all font-bold text-sm ${prefix ? 'pl-9' : 'pl-3'} ${
            highlight 
              ? 'bg-indigo-50 border-indigo-100 text-indigo-900 focus:border-indigo-500' 
              : 'bg-slate-50 border-slate-100 text-slate-800 focus:border-indigo-400'
          } ${suffix ? 'pr-8' : ''}`}
        />
        {suffix && <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold pointer-events-none">{suffix}</span>}
      </div>
    </div>
  );
};

