      ctx.fillStyle = '#94a3b8';
      ctx.font = 'bold 18px Inter, sans-serif';
      ctx.fillText(label.toUpperCase(), 50, y);
      ctx.fillStyle = color;
      ctx.font = 'bold 28px Inter, sans-serif';
      ctx.textAlign = 'right';
      ctx.fillText(value, width - 50, y);
      ctx.textAlign = 'left';
      y += 60;
