    ctx.fillStyle = '#94a3b8';
    ctx.font = 'bold 20px Inter, sans-serif';
    ctx.fillText('RETORNO (ROI)', 90, cardY + 160);

    ctx.fillStyle = results.roi >= 10 ? '#34d399' : '#818cf8';
    ctx.font = '900 60px Inter, sans-serif';
    ctx.fillText(formatPercent(results.roi), 90, cardY + 230);

    // Suggested Sale Price
