    const title = `${state.carModel || 'Repasse Pro'}`;
    const text = `🚗 ${title} (${state.carYear})\n💰 Lucro: ${formatBRL(results.netProfit)}\n🚀 ROI: ${formatPercent(results.roi)}`;
    if (navigator.share) {
      navigator.share({ title, text }).catch(copyResults);
    } else {
