      ctx.fillText(l.toUpperCase(), 120, y);
      ctx.textAlign = 'right'; ctx.fillStyle = '#ffffff'; ctx.fillText(v, 680, y);
      y += 50;
    };

    drawLine('Investimento Total', formatBRL(results.totalCost));
    drawLine('Preço de Venda', formatBRL(results.salePrice));
