    // Footer
    ctx.textAlign = 'center'; ctx.fillStyle = '#334155'; ctx.font = 'bold 16px Inter, sans-serif';
    ctx.fillText('FABIANO AUTO REPASSE © 2025', 400, 950);

    const link = document.createElement('a');
    link.download = `Fabiano_Repasse_${state.carModel || 'Carro'}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
