interface MoneyInputProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  prefix?: string;
  suffix?: string;
  className?: string;
  highlight?: boolean;
}

const MoneyInput: React.FC<MoneyInputProps> = ({ 
  label, value, onChange, prefix, suffix, className, highlight 
}) => {
  const [displayValue, setDisplayValue] = useState("");
  const isFocused = useRef(false);

  const formatValue = (val: number) => val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  useEffect(() => {
    if (!isFocused.current) setDisplayValue(value === 0 ? "" : formatValue(value));
  }, [value]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value;
    const validChars = raw.replace(/[^0-9.,-]/g, '');
    setDisplayValue(validChars);
    const normalized = parseFloat(validChars.replace(/\./g, '').replace(',', '.'));
    if (!isNaN(normalized)) onChange(normalized);
    else if (validChars === "") onChange(0);
  };

  const handleFocus = () => {
    isFocused.current = true;
    if (value !== 0) setDisplayValue(value.toString().replace('.', ','));
  };

  const handleBlur = () => {
    isFocused.current = false;
    const numeric = parseFloat(displayValue.replace(/\./g, '').replace(',', '.'));
    if (!isNaN(numeric)) {
      setDisplayValue(formatValue(numeric));
      onChange(numeric);
    } else {
      setDisplayValue("");
      onChange(0);
    }
  };

  return (
    <div className={className}>
      <label className="text-[8px] font-black uppercase tracking-widest block mb-0.5 text-slate-400">
        {label}
      </label>
      <div className="relative">
        {prefix && <span className="absolute left-2.5 top-1/2 -translate-y-1/2 text-cyan-500 text-[10px] font-black pointer-events-none">{prefix}</span>}
        <input
          type="text"
          inputMode="decimal"
          value={displayValue}
          onChange={handleChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
          placeholder="0,00"
          className={`w-full border rounded-lg py-2 pr-2 outline-none transition-all font-bold text-xs ${prefix ? 'pl-7' : 'pl-2'} ${
            highlight 
              ? 'bg-cyan-950/30 border-cyan-500/50 text-cyan-200' 
              : 'bg-slate-800/50 border-slate-700 text-slate-100 focus:border-cyan-500'
          } ${suffix ? 'pr-6' : ''}`}
        />
        {suffix && <span className="absolute right-2 top-1/2 -translate-y-1/2 text-cyan-500 text-[10px] font-black pointer-events-none">{suffix}</span>}
      </div>
    </div>
  );
};

