interface MoneyInputProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  prefix?: string;
  suffix?: string;
  className?: string;
  highlight?: boolean;
}

const MoneyInput: React.FC<MoneyInputProps> = ({ 
  label, value, onChange, prefix, suffix, className, highlight 
}) => {
  const [displayValue, setDisplayValue] = useState("");
  const isFocused = useRef(false);

  const formatValue = (val: number) => val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  useEffect(() => {
    if (!isFocused.current) setDisplayValue(value === 0 ? "" : formatValue(value));
  }, [value]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value;
    const validChars = raw.replace(/[^0-9.,-]/g, '');
    setDisplayValue(validChars);
    const normalized = parseFloat(validChars.replace(/\./g, '').replace(',', '.'));
    if (!isNaN(normalized)) onChange(normalized);
    else if (validChars === "") onChange(0);
  };

  const handleFocus = () => {
    isFocused.current = true;
    if (value !== 0) setDisplayValue(value.toString().replace('.', ','));
  };

  const handleBlur = () => {
    isFocused.current = false;
    const numeric = parseFloat(displayValue.replace(/\./g, '').replace(',', '.'));
    if (!isNaN(numeric)) {
      setDisplayValue(formatValue(numeric));
      onChange(numeric);
    } else {
      setDisplayValue("");
      onChange(0);
    }
  };

  return (
    <div className={className}>
      <label className="text-[7px] font-black uppercase tracking-widest block mb-0.5 text-slate-500">
        {label}
      </label>
      <div className="relative">
        {prefix && <span className="absolute left-2 top-1/2 -translate-y-1/2 text-cyan-500 text-[9px] font-black pointer-events-none">{prefix}</span>}
        <input
          type="text"
          inputMode="decimal"
          value={displayValue}
          onChange={handleChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
          placeholder="0,00"
          className={`w-full border rounded-md py-1 pr-1 outline-none transition-all font-bold text-[11px] ${prefix ? 'pl-6' : 'pl-1.5'} ${
            highlight 
              ? 'bg-cyan-950/20 border-cyan-500/40 text-cyan-200' 
              : 'bg-slate-800/40 border-slate-700/50 text-slate-100 focus:border-cyan-500'
          } ${suffix ? 'pr-5' : ''}`}
        />
        {suffix && <span className="absolute right-1.5 top-1/2 -translate-y-1/2 text-cyan-500 text-[9px] font-black pointer-events-none">{suffix}</span>}
      </div>
    </div>
  );
};

