            <span 
              className="text-[9px] font-black text-white px-2.5 py-1 rounded-md shadow-lg transition-colors min-w-[55px] text-center"
              style={{ backgroundColor: qualityColor, boxShadow: `0 4px 10px ${qualityColor}30` }}
